const rawInput = $json.appointment_datetime || '2025-07-01 08:00';

// Normalize input: ensure it has a 'T' and seconds
let input = rawInput.replace(' ', 'T');
if (!input.includes(':')) input += 'T00:00:00';
if (input.length === 16) input += ':00'; // Add seconds if missing

// Split into date and time parts
const [datePart, timePart] = input.split('T');
const [year, month, day] = datePart.split('-').map(Number);
const [hour, minute, second] = timePart.split(':').map(Number);

// Adjust Pacific Time (UTC-7 during DST)
const pacificOffset = -7;
const utcDate = new Date(Date.UTC(year, month - 1, day, hour - pacificOffset, minute, second));

// Format as UTC ISO string
const utcIso = utcDate.toISOString();

return [
  {
    json: {
      appointment_datetime: utcIso
    }
  }
];

